private void CacheLabelNames(ITransformer model, DataViewSchema schema)
{
    var predEngine = _mlContext.Model.CreatePredictionEngine<TicketInput, TicketPrediction>(model, schema);
    var scoreColumn = predEngine.OutputSchema["Score"];
    var slotNames = new VBuffer<ReadOnlyMemory<char>>();
    scoreColumn.Annotations.GetValue("SlotNames", ref slotNames);
    LabelNames = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
}

